package com.seaquake6324.civitas.domain.population;
import static org.junit.jupiter.api.Assertions.*;import org.junit.jupiter.api.Test;
class AdoptionRulesTest{@Test void distanceAndRealCapacityAreHardWhileConditionsExplainScore(){AdoptionRules rules=new AdoptionRules();var candidate=new AdoptionRules.Candidate(2,false,2,8,80,70,60,90);var near=rules.evaluate(candidate,32,128);assertTrue(near.eligible());assertTrue(near.score()>0);assertEquals(6,near.components().size());assertFalse(rules.evaluate(candidate,129,128).eligible());assertFalse(rules.evaluate(new AdoptionRules.Candidate(2,false,0,8,100,100,100,100),1,128).eligible());var players=new AdoptionRules.Candidate(2,true,2,8,100,100,100,100);assertEquals("player_consent_required",rules.evaluate(players,1,128).reason());assertTrue(rules.evaluate(players,1,128,true).eligible());}
@Test void everyPlayerGuardianMustConfirm(){java.util.UUID a=java.util.UUID.randomUUID(),b=java.util.UUID.randomUUID();AdoptionConsent consent=new AdoptionConsent(java.util.UUID.randomUUID(),java.util.UUID.randomUUID(),java.util.UUID.randomUUID(),java.util.UUID.randomUUID(),java.util.Set.of(FamilyMemberRef.player(a),FamilyMemberRef.player(b)),java.util.Set.of(a,b),java.util.Set.of(a),null,"minecraft:overworld",0,1,100,1);assertFalse(consent.complete());assertTrue(consent.confirm(b).complete());assertThrows(IllegalArgumentException.class,()->consent.confirm(java.util.UUID.randomUUID()));}}
